window.docContents[46].resolve({"/Analytic-Number-Theory/The-Bombieri___Vinogradov-theorem/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Analytic-Number-Theory--The-Bombieri___Vinogradov-theorem":{"contents":"The lean-bombieri-vinogradov project (Mellendijk) formalises the Bombieri–Vinogradov theorem on the\ndistribution of primes in arithmetic progressions on average, following Koukoulopoulos. The headline\ntheorem and its -intermediate are stated and the proof skeleton (Vaughan\ndecomposition) is in place but still carries sorry; the Siegel–Walfisz theorem and the large sieve\ninequality are taken as axioms. The node below is informal, linking to its source at commit\n08696dd.\n\n\n\n","context":"AINTLIB — An Atlas of Number Theory in Lean\u0009Analytic Number Theory","header":"2.13. The Bombieri–Vinogradov theorem","id":"/Analytic-Number-Theory/The-Bombieri___Vinogradov-theorem/#AINTLIB-___-An-Atlas-of-Number-Theory-in-Lean--Analytic-Number-Theory--The-Bombieri___Vinogradov-theorem"}});